import{_ as t,o as a,c as r,an as o}from"./chunks/framework.ubcH7j8_.js";const p=JSON.parse('{"title":"Why A.R.C.?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/why-arc.md","filePath":"guide/why-arc.md","lastUpdated":1773164166000}'),i={name:"guide/why-arc.md"};function n(s,e,l,d,c,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="why-a-r-c" tabindex="-1">Why A.R.C.? <a class="header-anchor" href="#why-a-r-c" aria-label="Permalink to &quot;Why A.R.C.?&quot;">​</a></h1><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>Building a production AI agent platform today means weeks of infrastructure work before you write a single line of agent logic. Teams cobble together API gateways, secrets managers, message brokers, vector databases, and observability stacks — only to discover that none of them talk to each other out of the box. The result is fragile, hand-wired plumbing that breaks under pressure and resists change.</p><p>Vendor lock-in compounds the problem. Many &quot;open-source&quot; AI platforms ship under restrictive licenses (BSL, source-available, non-compete clauses) that limit how you deploy and scale. When you need to swap a component, you discover your architecture is welded to a single vendor&#39;s SDK. Meanwhile, observability and resilience testing remain afterthoughts, bolted on months later when production incidents force the issue.</p><p>A.R.C. was built to fix this: a platform that ships production-ready infrastructure on day one, stays genuinely open-source, and treats every service as swappable.</p><h2 id="traditional-vs-the-a-r-c-way" tabindex="-1">Traditional vs. The A.R.C. Way <a class="header-anchor" href="#traditional-vs-the-a-r-c-way" aria-label="Permalink to &quot;Traditional vs. The A.R.C. Way&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Traditional</th><th>The A.R.C. Way</th></tr></thead><tbody><tr><td>Days spent wiring infrastructure</td><td><code>arc run --profile think</code> — done</td></tr><tr><td>Manual service integration</td><td>Pre-integrated: Heimdall, Flash, Sherlock, Scarlett, and more</td></tr><tr><td>Risk of vendor lock-in</td><td>100% open-source, open standards</td></tr><tr><td>Painful observability setup</td><td>OTEL + Friday Collector in every profile</td></tr><tr><td>Scaling bottlenecks</td><td>Event-driven, horizontally scalable</td></tr><tr><td>Steep learning curves</td><td>Production-ready in minutes</td></tr><tr><td>Unknown resilience</td><td>Health checks and structured runbook from day one</td></tr></tbody></table><h2 id="eight-reasons-teams-choose-a-r-c" tabindex="-1">Eight Reasons Teams Choose A.R.C. <a class="header-anchor" href="#eight-reasons-teams-choose-a-r-c" aria-label="Permalink to &quot;Eight Reasons Teams Choose A.R.C.&quot;">​</a></h2><h3 id="_1-minutes-not-months" tabindex="-1">1. Minutes, Not Months <a class="header-anchor" href="#_1-minutes-not-months" aria-label="Permalink to &quot;1. Minutes, Not Months&quot;">​</a></h3><p>One command deploys the full platform. <code>arc run --profile think</code> handles what takes teams weeks to configure manually: gateway routing, database provisioning, message broker wiring, OTEL collection, and service discovery. Your platform is running before your coffee gets cold.</p><h3 id="_2-100-foss" tabindex="-1">2. 100% FOSS <a class="header-anchor" href="#_2-100-foss" aria-label="Permalink to &quot;2. 100% FOSS&quot;">​</a></h3><p>Every service in the A.R.C. stack ships under Apache 2.0, MIT, or MPL. No BSL, no &quot;source-available&quot; fine print, no non-compete clauses. A.R.C. is built on a foundation you can fork, modify, and deploy without legal surprises.</p><h3 id="_3-platform-not-library" tabindex="-1">3. Platform, Not Library <a class="header-anchor" href="#_3-platform-not-library" aria-label="Permalink to &quot;3. Platform, Not Library&quot;">​</a></h3><p>A.R.C. is not another <code>pip install</code>. It is a complete ecosystem of pre-wired services: API gateway (Heimdall), secrets vault (Nick Fury), feature flags (Mystique), event streaming (Flash + Dr. Strange), persistent memory (Oracle), reasoning engine (Sherlock), voice pipeline (Scarlett), and full observability (Friday). You pick the profile; we handle the integration.</p><h3 id="_4-production-from-day-one" tabindex="-1">4. Production from Day One <a class="header-anchor" href="#_4-production-from-day-one" aria-label="Permalink to &quot;4. Production from Day One&quot;">​</a></h3><p>Observability is not an afterthought. Secrets management is not a post-launch scramble. A.R.C. ships with built-in telemetry collection (Friday Collector, OTLP :4317), structured logging, and health checks from the first <code>arc run</code>. The <code>ultra-instinct</code> profile adds SigNoz (Friday UI, :3301) for full traces + metrics.</p><h3 id="_5-zero-vendor-lock-in" tabindex="-1">5. Zero Vendor Lock-In <a class="header-anchor" href="#_5-zero-vendor-lock-in" aria-label="Permalink to &quot;5. Zero Vendor Lock-In&quot;">​</a></h3><p>A.R.C. is built on open standards. Feature flags use Unleash with OpenFeature compatibility — swap providers without rewriting. Observability uses OpenTelemetry — your telemetry pipeline is portable. Every infrastructure service can be replaced without rewriting your agent logic.</p><h3 id="_6-polyglot-architecture-—-two-brain-separation" tabindex="-1">6. Polyglot Architecture — Two-Brain Separation <a class="header-anchor" href="#_6-polyglot-architecture-—-two-brain-separation" aria-label="Permalink to &quot;6. Polyglot Architecture — Two-Brain Separation&quot;">​</a></h3><p>Go handles infrastructure: the CLI, bootstrap service (Cortex), and gateway run at compiled speed with no runtime dependencies. Python drives intelligence: Sherlock (LangGraph), Scarlett (Voice Agent), and the SDK use the full Python AI ecosystem. You get the right tool for each layer.</p><h3 id="_7-capability-driven-composition" tabindex="-1">7. Capability-Driven Composition <a class="header-anchor" href="#_7-capability-driven-composition" aria-label="Permalink to &quot;7. Capability-Driven Composition&quot;">​</a></h3><p>The profile system lets you scale up incrementally:</p><table tabindex="0"><thead><tr><th>Profile</th><th>What starts</th><th>Use case</th></tr></thead><tbody><tr><td><code>think</code></td><td>Core only (7 services)</td><td>Fast iteration, no LLM engine</td></tr><tr><td><code>reason</code></td><td>Core + Sherlock</td><td>Standard AI development</td></tr><tr><td><code>ultra-instinct</code></td><td>Core + all capabilities</td><td>Full platform: voice, observability, security, storage</td></tr></tbody></table><h3 id="_8-the-codename-system" tabindex="-1">8. The Codename System <a class="header-anchor" href="#_8-the-codename-system" aria-label="Permalink to &quot;8. The Codename System&quot;">​</a></h3><p>Every A.R.C. service has a memorable codename that reflects its role. Heimdall guards the gate. Sherlock reasons through problems. Flash carries messages at speed. Scarlett handles voice. This makes architecture discussions natural and the system easy to learn. See the full <a href="/arc-platform/docs/services/">Service Map</a>.</p><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><p><strong>Voice-First AI Companions</strong> — Scarlett (Voice Agent, port 8803) and Daredevil (LiveKit, port 7880) deliver low-latency, human-grade conversations with full WebRTC support. Enable with the <code>voice</code> capability in <code>ultra-instinct</code>.</p><p><strong>Stateful Research Agents</strong> — Sherlock (LangGraph, port 8802) and Oracle (PostgreSQL + pgvector, port 5432) keep long-running investigations grounded in persistent, queryable memory. Available in <code>reason</code> and <code>ultra-instinct</code> profiles.</p><p><strong>Scalable AI Platforms</strong> — Use A.R.C. as the foundation for enterprise AI product suites: event-driven microservices via Flash (NATS) and Dr. Strange (Pulsar), feature flags via Mystique (Unleash), and full observability via Friday — all included.</p><hr><p>Ready? <strong><a href="/arc-platform/docs/guide/getting-started.html">Get Started →</a></strong></p>',31)])])}const m=t(i,[["render",n]]);export{p as __pageData,m as default};
